(function(){$(document).ready(function(){$(".notes-col").hide();$("td.notes-col").each(function(){if($(this).text()!=="-"){$(".notes-col").show()}});if($(".actions-col").length>1){$(".actions-col").css("opacity",0.5);$("tr").hover(function(){$(this).find(".actions-col").fadeTo(100,1)},function(){$(this).find(".actions-col").fadeTo(100,0.5)})}var $selectAll=$("#bulk-select-all");var $bulkActions=$("#bulk-actions");function updateBulkState(){var checked=$(".bulk-check:checked").length;if(checked>0){$bulkActions.show()}else{$bulkActions.hide()}var total=$(".bulk-check:visible").length;$selectAll.prop("checked",checked>0&&checked===total);$selectAll.prop("indeterminate",checked>0&&checked<total)}$selectAll.on("change",function(){$(".bulk-check:visible").prop("checked",this.checked);updateBulkState()});$(document).on("change",".bulk-check",updateBulkState);$("#bulk-form").on("submit",function(e){var action=$(document.activeElement).val();var count=$(".bulk-check:checked").length;var msg=action==="delete"?count+" Buchung(en) endgültig löschen?":count+" Buchung(en) stornieren?";if(!confirm(msg)){e.preventDefault()}})})})();
